import React from "react";
import {MenuItem, Menu, Sidebar, SubMenu} from 'react-pro-sidebar';
import '.'


function App() {
  return (
    <div className="App">
      <header className="App-header">
        <p>
          Hello Welcome to me Warehouse Inventory application!
        </p>
        <Sidebar>
          <Menu>
            <SubMenu label="Menu">
              <MenuItem>Dashboard</MenuItem>
              <MenuItem>Inventory</MenuItem>
              <MenuItem>Reports</MenuItem>
              <MenuItem>Logout</MenuItem>
            </SubMenu>
          </Menu>
        </Sidebar>
      </header>
    </div>
  );
}

export default App;
